SELECT AVG(size) AS average_size
FROM torrents
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Other');

SELECT COUNT(access_id) AS total_accesses
FROM access_logs
WHERE content_id = (SELECT content_id FROM content WHERE title = 'PornWorld 23 05 26 Eveline Dellai And Silvia Dellai XXX 1080p');

SELECT user_id, COUNT(content_id) AS num_reviews
FROM content_reviews
GROUP BY user_id;

SELECT MAX(upload_date) 
FROM content_versions 
WHERE content_id = 0;

SELECT c.title
FROM content AS c
INNER JOIN torrents AS t ON c.content_id = t.content_id
WHERE t.seed = (
    SELECT MAX(seed) FROM torrents
);
